import{_ as t,o as a,c as i,a2 as e}from"./chunks/framework.DvFsUg-r.js";const p=JSON.parse('{"title":"작업 기록","description":"","frontmatter":{},"headers":[],"relativePath":"skills-talk/worklog/index.md","filePath":"skills-talk/worklog/index.md","lastUpdated":1781092690000}'),o={name:"skills-talk/worklog/index.md"};function l(n,s,r,h,d,c){return a(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="작업-기록" tabindex="-1">작업 기록 <a class="header-anchor" href="#작업-기록" aria-label="Permalink to &quot;작업 기록&quot;">​</a></h1><p>이 섹션(<code>/skills-talk/</code>)이 <strong>Agent 설계 저널</strong> 블로그에 어떻게 들어왔는지, 그리고 원본 콘텐츠가 어떻게 만들어졌는지를 기록한다.</p><div class="info custom-block"><p class="custom-block-title">이 섹션의 출처</p><p>이 강연 분석은 원래 별도의 VitePress 프로젝트 (<code>youtube-do-not-build-agents</code>)로 제작된 것이다. 본 저장소는 그 사이트의 시각 테마를 차용해 <a href="/journal/2026-06-01-vitepress-migration">Docusaurus → VitePress 이관</a> 을 진행했고, 이후 강연 콘텐츠 자체도 이 블로그의 <strong>참고 자료 섹션</strong>으로 가져왔다. 즉 이 페이지 아래쪽의 &quot;원본 제작 기록&quot;은 외부 프로젝트의 기록이고, 바로 다음의 &quot;이 블로그로의 편입&quot;이 본 저장소 맥락의 작업 기록이다.</p></div><hr><h2 id="이-블로그로의-편입-본-저장소-작업" tabindex="-1">이 블로그로의 편입 (본 저장소 작업) <a class="header-anchor" href="#이-블로그로의-편입-본-저장소-작업" aria-label="Permalink to &quot;이 블로그로의 편입 (본 저장소 작업)&quot;">​</a></h2><ul><li><strong>편입 경위</strong> — 본 저장소(Spring AI + langgraph4j 에이전트를 SDD 로 만드는 기록)의 문서 사이트를 VitePress 로 이관(feature 007)하면서 이 강연 사이트의 퍼블리케이션 테마를 그대로 채택했고, 같은 톤이라 강연 콘텐츠도 함께 실었다. &quot;에이전트 말고 스킬을 만들어라&quot;는 본 저장소의 SDD·스킬 지향과 결이 맞는 참고 자료다.</li><li><strong>네임스페이스 분리</strong> — 본 블로그엔 이미 자체 <code>개요(/overview/)</code>·<code>저널</code>· <code>명세(/specs/)</code> 가 있어, 강연 콘텐츠는 <strong><code>/skills-talk/</code></strong> 아래로 분리해 충돌을 피했다. 원본의 절대 링크(<code>/overview/</code>·<code>/topics/</code> 등)는 모두 <code>/skills-talk/…</code> 로 교정했다.</li><li><strong>네비게이션</strong> — 상단 nav 에 &quot;스킬 강연&quot;, 좌측에 전용 사이드바(개요·전문· 주제별·작업로그) 4그룹을 추가했다. 홈에는 안내용 feature 카드를 하나 두었다.</li><li><strong>테마</strong> — 본문 폭을 좁히던 퍼블리케이션 기본값을 풀어 사이트 전체가 전체폭 레이아웃을 쓰도록 했고(메뉴·목차는 고정), 이 섹션도 그 설정을 공유한다.</li></ul><h2 id="실행·배포-본-저장소-기준" tabindex="-1">실행·배포 (본 저장소 기준) <a class="header-anchor" href="#실행·배포-본-저장소-기준" aria-label="Permalink to &quot;실행·배포 (본 저장소 기준)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blog</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # http://localhost:5173/skills-talk/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 정적 산출물 → blog/.vitepress/dist</span></span></code></pre></div><p><code>main</code> 에 푸시하면 GitHub Actions(<code>publish-blog.yml</code>)가 specs 동기화 → VitePress 빌드(깨진 내부 링크가 있으면 실패하는 strict 모드) → 게시 저장소 (<code>coffeeman1.github.io</code>) 루트로 배포를 수행한다. 공개 경로는 <code>https://coffeeman1.github.io/skills-talk/</code> 다.</p><hr><h2 id="원본-콘텐츠-제작-기록-외부-프로젝트" tabindex="-1">원본 콘텐츠 제작 기록 (외부 프로젝트) <a class="header-anchor" href="#원본-콘텐츠-제작-기록-외부-프로젝트" aria-label="Permalink to &quot;원본 콘텐츠 제작 기록 (외부 프로젝트)&quot;">​</a></h2><blockquote><p>아래는 강연 분석 콘텐츠가 원래 어떻게 만들어졌는지에 대한 기록으로, 본 저장소가 아니라 원본 프로젝트(<code>youtube-do-not-build-agents</code>)의 맥락이다.</p></blockquote><h3 id="문서의-목적" tabindex="-1">문서의 목적 <a class="header-anchor" href="#문서의-목적" aria-label="Permalink to &quot;문서의 목적&quot;">​</a></h3><p>2025년 12월 8일 AI Engineer 컨퍼런스에서 공개된 Anthropic의 <strong>&quot;Don&#39;t Build Agents, Build Skills Instead&quot;</strong> 발표를 한국어로 정리하고 분석하기 위해 만들어졌다. 발표자는 Anthropic의 엔지니어 Barry Zhang과 Mahesh Murag이며, 발표 길이는 약 16분이다.</p><p>발표는 짧지만 밀도가 높다. 에이전트 설계의 방향 전환, Agent Skills라는 새로운 개념, 점진적 공개의 엔지니어링 원리, 그리고 조직 지식의 물질화라는 비전까지 -- 한 편의 선언문이자 실무 가이드에 가깝다. 이 문서는 그 밀도를 풀어 주제별로 읽을 수 있게 재구성한 결과물이다.</p><h3 id="소스" tabindex="-1">소스 <a class="header-anchor" href="#소스" aria-label="Permalink to &quot;소스&quot;">​</a></h3><ol><li><strong>원본 YouTube 영상</strong> -- <a href="https://www.youtube.com/watch?v=CEvIs9y1uog" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=CEvIs9y1uog</a></li><li><strong>공개된 요약과 타임스탬프</strong> -- Lilys.ai, Video Highlight, YoutubeSummary 등의 요약 서비스</li><li><strong>Anthropic 공식 블로그</strong> -- Agent Skills 발표 포스트 및 엔지니어링 글</li><li><strong>업계 논평</strong> -- X(구 Twitter), OutcomeOps, BRGR 등의 글</li></ol><h3 id="구조" tabindex="-1">구조 <a class="header-anchor" href="#구조" aria-label="Permalink to &quot;구조&quot;">​</a></h3><ul><li><strong>개요(<code>/skills-talk/overview/</code>)</strong> -- 소개, 핵심 요약, 주요 인물</li><li><strong>전문(<code>/skills-talk/transcript/</code>)</strong> -- 타임스탬프별 발언 기록과 한국어 번역</li><li><strong>주제별(<code>/skills-talk/topics/</code>)</strong> -- 7개 핵심 주제의 심층 분석</li><li><strong>작업로그(<code>/skills-talk/worklog/</code>)</strong> -- 본 문서</li></ul><h3 id="번역-원칙" tabindex="-1">번역 원칙 <a class="header-anchor" href="#번역-원칙" aria-label="Permalink to &quot;번역 원칙&quot;">​</a></h3><ul><li><strong>원문 대 번역 병치</strong> -- 발언은 영어 원문을 먼저 노출하고, <code>::: details</code> 블록에 한국어 번역을 넣었다. 클릭해서 펼쳐보는 방식이다.</li><li><strong>의역 우선</strong> -- 직역보다는 한국어 독자가 자연스럽게 읽을 수 있는 어조를 택했다.</li><li><strong>고유명사 처리</strong> -- Barry Zhang, Mahesh Murag, Claude, Anthropic 등은 로마자 원형을 유지하되, 본문에서 맥락상 필요한 곳에는 한글 표기를 병기했다.</li></ul><h3 id="한계와-주의" tabindex="-1">한계와 주의 <a class="header-anchor" href="#한계와-주의" aria-label="Permalink to &quot;한계와 주의&quot;">​</a></h3><ul><li><strong>완전한 축자 녹취가 아님</strong> -- 전문(transcript)은 공개된 요약과 타임스탬프를 기반으로 재구성한 편집본이다. 발언의 정확한 표현은 원본 영상에서 확인해야 한다.</li><li><strong>발표 이후의 업데이트는 반영되지 않음</strong> -- 2025년 12월 발표 시점의 내용을 기준으로 하며, 그 이후 Anthropic이 발표한 Agent Skills 관련 추가 정책/기능은 포함되지 않는다.</li><li><strong>주제별 분석의 해석</strong> -- 7개 주제별 글에는 발표 내용을 바탕으로 한 해석과 배경 설명이 포함된다. 발표자들의 발언 자체와 구분해 읽을 필요가 있다.</li></ul>`,23)])])}const k=t(o,[["render",l]]);export{p as __pageData,k as default};
